/* ─────────────────────────────────────────────
   NGSSAI — Ticket Handler Module
   v2.30.0 · home_page.js'den ayrıştırıldı
   Ticket hata işleme, async sonuç, sıfırlama
   ───────────────────────────────────────────── */

// 🆘 Ticket hatası işle
function handleTicketError(error, suggestBtn, problemTextArea) {
    console.error('[NGSSAI] Ticket hatası:', error);
    const loadingBox = document.getElementById("loadingBox");
    if (loadingBox) loadingBox.classList.add("hidden");

    // 🌐 VPN/Network hatası kontrolü
    if (window.isVPNNetworkError && window.isVPNNetworkError(error)) {
        window.showVPNErrorPopup();
    } else if (typeof VyraToast !== 'undefined') {
        VyraToast.error('Çözüm hazırlanamadı: ' + error);
    } else {
        VyraModal.error({ title: 'Hata', message: 'Çözüm hazırlanamadı: ' + error });
    }

    isProcessingRequest = false;
    if (suggestBtn) {
        suggestBtn.disabled = false;
        suggestBtn.classList.remove("loading");
        suggestBtn.innerHTML = "Çözüm Öner";
    }
    if (problemTextArea) problemTextArea.disabled = false;
}

// 🚀 Asenkron ticket sonucunu işle (WebSocket'ten gelen)
function handleAsyncTicketResult(result) {
    if (!result) return;

    // ⏱️ Yanıt süresini hesapla
    const responseTime = ((performance.now() - requestStartTime) / 1000).toFixed(1);
    const responseTimeEl = document.getElementById("responseTime");
    if (responseTimeEl) {
        responseTimeEl.textContent = `${responseTime}s`;
    }

    const loadingBox = document.getElementById("loadingBox");
    const finalSolutionBox = document.getElementById("finalSolutionBox");
    const solutionSteps = document.getElementById("solutionSteps");
    const cymText = document.getElementById("cymText");
    const suggestBtn = document.getElementById("suggestBtn");

    if (loadingBox) loadingBox.classList.add("hidden");
    if (finalSolutionBox) finalSolutionBox.classList.remove("hidden");

    // Kullanıcı talebini göster
    const userRequestTextEl = document.getElementById("userRequestText");
    const problemTextAreaSource = document.getElementById("problemText");
    if (userRequestTextEl && problemTextAreaSource) {
        userRequestTextEl.textContent = problemTextAreaSource.value || result.description || "-";
    }

    if (solutionSteps) {
        solutionSteps.innerHTML = "";
        const solutionHtml = formatSolutionForDisplay(result.final_solution);
        solutionSteps.innerHTML = solutionHtml;

        // Kaynak bilgisini göster
        updateSourceInfo(result.final_solution);
    }

    // ÇYM text
    if (cymText) cymText.textContent = result.cym_text || "ÇYM metni oluşturulamadı.";

    // 🎫 Ticket ID'yi SolutionDisplayModule'a kaydet (LLM değerlendirmesi için)
    if (result.id && window.SolutionDisplayModule?.setTicketInfo) {
        window.SolutionDisplayModule.setTicketInfo(result.id, [], problemTextAreaSource?.value || '');
        console.log('[NGSSAI] Ticket ID kaydedildi:', result.id);
    }

    // ✅ Çözüm verildi - butonu "Yeni Soru" olarak değiştir (v2.24.0)
    solutionProvided = true;
    if (suggestBtn) {
        suggestBtn.innerHTML = '<i class="fa-solid fa-plus"></i> Yeni Soru';
        suggestBtn.classList.add("new-request-mode");
        suggestBtn.disabled = false;
    }

    // Keyboard hint'i gizle
    const keyboardHint = document.querySelector('.keyboard-hint');
    if (keyboardHint) keyboardHint.style.display = 'none';

    // ✅ Textarea'yı disabled tut (çözüm gösterilirken yazılmasın)
    const problemTextArea = document.getElementById("problemText");
    if (problemTextArea) problemTextArea.disabled = true;

    // Ticket history'yi yenile
    if (typeof loadTicketHistory === 'function') {
        loadTicketHistory(true);
    }
}

// Ekranları sıfırla ve yeni soru moduna geç (v2.24.0)
function resetToNewRequest() {
    // Textarea'yı temizle ve ENABLE yap
    const problemTextArea = document.getElementById("problemText");
    if (problemTextArea) {
        problemTextArea.value = "";
        problemTextArea.disabled = false;  // ✅ Yeniden aktif et
        problemTextArea.focus();
    }

    // Görsel preview'ı temizle
    const imagePreviewContainer = document.getElementById("imagePreviewContainer");
    const imagePreview = document.getElementById("imagePreview");
    const imageInput = document.getElementById("imageInput");
    if (imagePreviewContainer) imagePreviewContainer.classList.add("hidden");
    if (imagePreview) imagePreview.src = "";
    if (imageInput) imageInput.value = "";

    // Çözüm kutusunu gizle
    finalSolutionBox.classList.add("hidden");
    loadingBox.classList.add("hidden");

    // CYM checkbox'ı sıfırla
    if (showCYM) showCYM.checked = false;
    if (cymContent) cymContent.classList.add("hidden");

    // Buton'u eski haline döndür
    suggestBtn.innerHTML = "Çözüm Öner";
    suggestBtn.classList.remove("new-request-mode");
    suggestBtn.disabled = true;
    solutionProvided = false;

    // Keyboard hint'i göster
    const keyboardHint = document.querySelector('.keyboard-hint');
    if (keyboardHint) keyboardHint.style.display = 'block';

    // Yanıt süresini sıfırla
    const responseTimeEl = document.getElementById("responseTime");
    if (responseTimeEl) responseTimeEl.textContent = "--";

    // Tooltip'i göster
    if (suggestTooltip) suggestTooltip.style.display = 'block';
}

// Progress element oluştur
function createProgressElement() {
    const loadingBox = document.getElementById("loadingBox");
    if (!loadingBox) return null;

    let progressEl = loadingBox.querySelector('.progress-text');
    if (!progressEl) {
        progressEl = document.createElement('p');
        progressEl.className = 'progress-text text-sm text-gray-400 mt-2';
        loadingBox.appendChild(progressEl);
    }
    return progressEl;
}

function updateProgress(el, text) {
    if (el) el.textContent = text;
}


/* === assets/js/modules/solution_formatter.js === */
/* ─────────────────────────────────────────────
   NGSSAI — Solution Formatter Module
   v2.30.0 · home_page.js'den ayrıştırıldı
   Çözüm formatlama fallback fonksiyonları
   ───────────────────────────────────────────── */


// =============================================
// ÇÖZÜM FORMATLAMA - SolutionDisplayModule Kullanılır
// (Kod tekrarı önlendi - tek kaynak: solution_display.js)
// =============================================

// SolutionDisplayModule wrapper - Modül yüklüyse onu kullan, değilse fallback
function formatSolutionForDisplay(solution) {
    if (!solution) return '<p class="text-gray-500">Çözüm bilgisi yok</p>';

    // SolutionDisplayModule modülünü kullan
    if (typeof window.SolutionDisplayModule !== 'undefined' && window.SolutionDisplayModule.format) {
        return window.SolutionDisplayModule.format(solution);
    }

    // Fallback - modül yüklü değilse basit format
    console.warn('[NGSSAI] SolutionDisplayModule yüklü değil, basit format kullanılıyor');
    return `<p class="solution-text">${escapeHtmlForSolution(solution)}</p>`;
}

// Inline numaralı adımları ayır: "1) step1 2) step2 3) step3" -> ayrı adımlar
function formatInlineNumberedSteps(text) {
    // Önce kaynak bilgisini al ve temizle
    let sourceInfo = '';
    const sourceMatch = text.match(/[💡📄]?\s*Kaynak:\s*(.+?)(?:\s*$|\.?\s*$)/i);
    if (sourceMatch) {
        sourceInfo = sourceMatch[1].trim();
        text = text.replace(sourceMatch[0], '').trim();
    }

    // --- ayracını temizle
    if (text.includes('---')) {
        text = text.split('---')[0].trim();
    }

    // İlk paragrafı (adımlardan önceki metin) ayır
    let introText = '';
    const firstStepMatch = text.match(/^(.+?)(?=\d+[\)\.]\s)/);
    if (firstStepMatch) {
        introText = firstStepMatch[1].trim();
        if (introText.endsWith(':')) {
            introText = introText.slice(0, -1).trim();
        }
    }

    // Adımları parse et - Geliştirilmiş regex
    // "1) ... 2) ... 3) ..." veya "1. ... 2. ... 3. ..." formatları
    const steps = [];
    const stepRegex = /(\d+)[\)\.]\s*([^0-9]+?)(?=\s*\d+[\)\.]|$)/g;
    let match;

    while ((match = stepRegex.exec(text)) !== null) {
        let stepContent = match[2].trim();

        // Kaynak bilgisini içeriyorsa temizle
        if (stepContent.toLowerCase().includes('kaynak:')) {
            stepContent = stepContent.split(/kaynak:/i)[0].trim();
        }

        // Çok kısa içerikleri atla
        if (stepContent.length > 3) {
            steps.push({
                num: parseInt(match[1]),
                content: stepContent
            });
        }
    }

    // Adım bulunamadıysa düz metin olarak döndür
    if (steps.length === 0) {
        return `<p class="solution-text">${escapeHtmlForSolution(text)}</p>`;
    }

    // HTML oluştur - Container ile sarmalı
    let html = '<div class="solution-steps-container">';

    // Giriş metni varsa ekle
    if (introText && introText.length > 10) {
        html += `<p class="solution-intro-text">${escapeHtmlForSolution(introText)}</p>`;
    }

    // Adımları ekle
    steps.forEach((step, index) => {
        let content = step.content;
        // Son karakteri kontrol et
        if (!content.endsWith('.') && !content.endsWith('!') && !content.endsWith('?')) {
            content += '.';
        }
        // İlk harfi büyüt
        content = content.charAt(0).toUpperCase() + content.slice(1);

        html += `
            <div class="solution-step-item">
                <div class="step-number">${index + 1}</div>
                <div class="step-content">${escapeHtmlForSolution(content)}</div>
            </div>
        `;
    });

    html += '</div>';

    // Kaynak bilgisi varsa ekle
    if (sourceInfo) {
        html += `
            <div class="source-info-box">
                <i class="fa-solid fa-lightbulb"></i>
                <span>Kaynak: ${escapeHtmlForSolution(sourceInfo)}</span>
            </div>
        `;
    }

    return html;
}

// Tek paragraf metni adımlara ayırır
function formatSingleParagraph(text) {
    // Adım ayırıcı kalıplar
    const stepPatterns = [
        /\.\s+(?=[A-ZÇĞİÖŞÜ])/g,  // Büyük harfle başlayan cümle
        /\.\s+(?=\d)/g,            // Sayı ile başlayan cümle
        /;\s+/g,                    // Noktalı virgül
    ];

    // Önce "ardından" veya "sonra" ile böl (en yaygın geçiş kelimeleri)
    if (/,\s*ardından\s+/i.test(text)) {
        sentences = text.split(/,\s*ardından\s+/i).filter(s => s.trim().length > 5);
    } else if (/,\s*sonra\s+/i.test(text)) {
        sentences = text.split(/,\s*sonra\s+/i).filter(s => s.trim().length > 5);
    } else if (text.includes(';')) {
        // Noktalı virgül ile ayrılmış adımlar
        sentences = text.split(/;\s*/).filter(s => s.trim().length > 5);
    } else {
        // Hiçbiri çalışmadıysa, nokta + büyük harf ile böl
        sentences = text.split(/\.\s+(?=[A-ZÇĞİÖŞÜ])/).filter(s => s.trim());
        // Yine de 1 cümle ise tek olarak bırak
        if (sentences.length < 2) {
            sentences = [text];
        }
    }

    // Kaynak bilgisini ayır
    let sourceInfo = '';
    const sourceMatch = text.match(/📄\s*Kaynak:\s*(.+?)(?:\s*$|\.\s)/i);
    if (sourceMatch) {
        sourceInfo = sourceMatch[1].trim();
    }

    // Cümleleri temizle ve adımlara dönüştür
    let html = '<div class="solution-steps-container">';
    let stepCounter = 0;

    sentences.forEach(sentence => {
        let cleanSentence = sentence.trim();

        // Kaynak satırını atla
        if (cleanSentence.toLowerCase().includes('kaynak:') || cleanSentence.startsWith('📄')) {
            return;
        }

        // Çok kısa cümleleri atla
        if (cleanSentence.length < 10) return;

        // Nokta ekle (yoksa)
        if (!cleanSentence.endsWith('.') && !cleanSentence.endsWith('!') && !cleanSentence.endsWith('?')) {
            cleanSentence += '.';
        }

        // İlk harfi büyük yap
        cleanSentence = cleanSentence.charAt(0).toUpperCase() + cleanSentence.slice(1);

        stepCounter++;

        html += `
            <div class="solution-step-item">
                <div class="step-number">${stepCounter}</div>
                <div class="step-content">${escapeHtmlForSolution(cleanSentence)}</div>
            </div>
        `;
    });

    html += '</div>';

    // Kaynak bilgisi ekle
    if (sourceInfo) {
        html += `
            <div class="solution-source">
                <i class="fa-solid fa-file-lines"></i>
                <span>Kaynak: ${escapeHtmlForSolution(sourceInfo)}</span>
            </div>
        `;
    }

    return html;
}

// Mevcut numaralı adım formatı
function formatSolutionWithSteps(solution) {
    const lines = solution.split('\n');
    let html = '';
    let inList = false;
    let inAlternative = false;
    let stepCounter = 0;
    let alternativeStepCounter = 0;

    lines.forEach(line => {
        const trimmedLine = line.trim();
        if (!trimmedLine) return;

        // "Alternatif olarak:" kontrolü
        const alternativeMatch = trimmedLine.match(/^alternatif(?:\s+olarak)?[:]/i);
        if (alternativeMatch) {
            if (inList) {
                html += '</div>';
                inList = false;
            }

            html += `
                <div class="solution-alternative-header">
                    <i class="fa-solid fa-shuffle"></i>
                    <span>Alternatif Olarak</span>
                </div>
            `;
            inAlternative = true;
            alternativeStepCounter = 0;
            return;
        }

        // Numaralı satır kontrolü
        const numberedMatch = trimmedLine.match(/^(\d+)[.\)]\s*(.+)/);

        if (numberedMatch) {
            if (!inList) {
                html += '<div class="solution-steps-container">';
                inList = true;
            }

            const counter = inAlternative ? ++alternativeStepCounter : ++stepCounter;
            const stepClass = inAlternative ? 'solution-step-item alternative' : 'solution-step-item';

            html += `
                <div class="${stepClass}">
                    <div class="step-number">${counter}</div>
                    <div class="step-content">${escapeHtmlForSolution(numberedMatch[2])}</div>
                </div>
            `;
        } else {
            if (inList) {
                html += '</div>';
                inList = false;
            }

            if (trimmedLine.startsWith('📄') || trimmedLine.toLowerCase().startsWith('kaynak:')) {
                html += `
                    <div class="solution-source">
                        <i class="fa-solid fa-file-lines"></i>
                        <span>Kaynak: ${escapeHtmlForSolution(trimmedLine.replace('📄', '').replace(/^kaynak:/i, '').trim())}</span>
                    </div>
                `;
            } else if (trimmedLine === '---') {
                html += '<hr class="solution-divider">';
            } else {
                html += `<p class="solution-text">${escapeHtmlForSolution(trimmedLine)}</p>`;
            }
        }
    });

    if (inList) html += '</div>';

    return html || `<p class="solution-text">${escapeHtmlForSolution(solution)}</p>`;
}

// HTML escape (Yeni Soru için)
function escapeHtmlForSolution(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// Kaynak bilgisini HTML elementine ekle
function updateSourceInfo(solution) {
    const sourceInfoBox = document.getElementById("sourceInfo");
    const sourceText = document.getElementById("sourceText");

    if (!sourceInfoBox || !sourceText) return;

    // Kaynak bilgisini çıkar
    const sourceMatch = solution?.match(/📄\s*Kaynak:\s*(.+?)(?:\s*$|\.)/i) ||
        solution?.match(/Kaynak:\s*(.+?)(?:\s*$|\.)/i);

    if (sourceMatch && sourceMatch[1]) {
        sourceText.textContent = "Kaynak: " + sourceMatch[1].trim();
        sourceInfoBox.classList.remove("hidden");
    } else {
        sourceInfoBox.classList.add("hidden");
    }
}


/* === assets/js/system_manager.js === */
/* ─────────────────────────────────────────────
   NGSSAI — Sistem Yönetim Modülü
   v2.30.0 · home_page.js'den ayrıştırıldı
   versiyon, session timer, sidebar profil, sistem sıfırlama
   ───────────────────────────────────────────── */

window.SystemManagerModule = (function () {

    const API_BASE_URL = window.API_BASE_URL || 'http://localhost:8002';

    // --- VERSİYON ---
    async function loadAppVersion() {
        try {
            const response = await fetch(`${API_BASE_URL}/api/health`);
            if (response.ok) {
                const data = await response.json();
                const versionEl = document.getElementById('appVersion');
                if (versionEl && data.version) {
                    versionEl.textContent = `v${data.version}`;
                }
            }
        } catch (err) {
            console.warn('[NGSSAI] Versiyon yüklenemedi:', err);
        }
    }

    // --- OTURUM SAYACI ---
    // v2.53.1: Sayaç son login zamanından itibaren sayar.
    // login.js başarılı girişte session_start_time'ı set eder.
    // PC kapansa/tarayıcı kapansa bile sonraki login'de sıfırlanır.
    // v3.28.1: 60 dk threshold -> 15 sn countdown popup -> refresh veya auto-logout.
    let sessionStartTime = null;
    let sessionTimerInterval = null;

    // v3.28.1 — Session timeout config
    const SESSION_WARN_AT_SECONDS = 60 * 60;       // 60 dakika
    const SESSION_LOGOUT_COUNTDOWN_SECONDS = 15;   // popup içi countdown

    let _sessionWarningShown = false;
    let _logoutTimeoutId = null;
    let _logoutCountdownInterval = null;
    let _previousFocusEl = null;

    function startSessionTimer() {
        // Login olmadan timer başlatma — access_token yoksa kullanıcı giriş yapmamış
        const token = localStorage.getItem('access_token');
        if (!token) return;

        const now = new Date();

        // v3.30.1: Gerçek login zamanı = JWT iat (issued-at).
        // session_start_time localStorage cache amaçlıdır; canonical kaynak JWT'dir.
        // Bu sayede checkExistingAuth auto-redirect veya başka bir yol session_start_time'ı
        // güncellemese bile sayaç yanlış başlamaz.
        //
        // Senaryo matrisi:
        //   1) Fresh login → iat = şimdi          → sayaç 0:00'dan başlar
        //   2) Sayfa yenileme (30 dk sonra)       → iat = 30 dk önce → sayaç 30:00'dan devam
        //   3) Eski token resume (>60 dk eski)    → iat çok eski   → sayaç sıfırla (yeni window)
        //   4) Sunucu clock skew (iat future)     → negatif age    → güvenli reset
        let baseTime;
        try {
            const payload = JSON.parse(atob(token.split('.')[1]));
            if (!payload || typeof payload.iat !== 'number') {
                throw new Error('JWT iat missing');
            }
            const tokenIssuedAt = new Date(payload.iat * 1000);
            const tokenAgeSec = Math.floor((now - tokenIssuedAt) / 1000);

            if (tokenAgeSec < 0 || tokenAgeSec >= SESSION_WARN_AT_SECONDS) {
                // Resume w/ stale token veya clock skew → fresh window
                baseTime = now;
            } else {
                // Yakın zamanda issue edilmiş token → gerçek login zamanını kullan
                baseTime = tokenIssuedAt;
            }
        } catch (e) {
            // Malformed JWT — defansif fallback
            const stored = localStorage.getItem('session_start_time');
            baseTime = stored ? new Date(stored) : now;
            // Stored da bayatsa reset
            if (Math.floor((now - baseTime) / 1000) >= SESSION_WARN_AT_SECONDS) {
                baseTime = now;
            }
        }

        sessionStartTime = baseTime;
        localStorage.setItem('session_start_time', baseTime.toISOString());

        updateSessionTimer();
        sessionTimerInterval = setInterval(updateSessionTimer, 1000);
    }

    function updateSessionTimer() {
        if (!sessionStartTime) return;

        const now = new Date();
        const diff = Math.floor((now - sessionStartTime) / 1000);

        const hours = Math.floor(diff / 3600);
        const minutes = Math.floor((diff % 3600) / 60);
        const seconds = diff % 60;

        const timerStr = [
            hours.toString().padStart(2, '0'),
            minutes.toString().padStart(2, '0'),
            seconds.toString().padStart(2, '0')
        ].join(':');

        const timerEl = document.getElementById('sessionTimer');
        if (timerEl) {
            timerEl.textContent = timerStr;
            if (diff > 3600) {
                timerEl.classList.remove('text-gray-400');
                timerEl.classList.add('text-yellow-400');
            }
        }

        // v3.28.1 — 60 dk dolunca tek-seferlik uyarı popup'ı
        if (diff >= SESSION_WARN_AT_SECONDS && !_sessionWarningShown) {
            _showSessionWarning();
        }
    }

    // ============================================================
    // v3.28.1 — Session Timeout Modal
    // ============================================================
    function _ensureWarningModal() {
        if (document.getElementById('sessionTimeoutModal')) return;
        const html = ''
            + '<div id="sessionTimeoutModal" class="modal-overlay session-timeout-overlay" '
            +      'role="dialog" aria-modal="true" aria-labelledby="sessionTimeoutTitle" hidden>'
            +   '<div class="modal-box session-timeout-box">'
            +     '<div class="modal-header">'
            +       '<h3 id="sessionTimeoutTitle">'
            +         '<i class="fa-solid fa-clock"></i> Oturum Süreniz Doluyor'
            +       '</h3>'
            +     '</div>'
            +     '<div class="modal-body">'
            +       '<p>60 dakikadır oturumdasınız. Oturumu sürdürmek istiyor musunuz?</p>'
            +       '<p class="session-countdown-line">'
            +         '<strong id="sessionLogoutCountdown">15</strong> saniye içinde otomatik çıkış yapılacak.'
            +       '</p>'
            +       '<div class="session-countdown-bar" aria-hidden="true">'
            +         '<div id="sessionCountdownFill" class="session-countdown-bar-fill"></div>'
            +       '</div>'
            +     '</div>'
            +     '<div class="modal-footer">'
            +       '<button id="sessionContinueBtn" type="button" class="btn btn-primary" '
            +               'data-tooltip="Oturumu sürdür">'
            +         '<i class="fa-solid fa-rotate"></i> Devam Et'
            +       '</button>'
            +     '</div>'
            +   '</div>'
            + '</div>';
        const container = document.createElement('div');
        container.innerHTML = html.trim();
        const modal = container.firstElementChild;
        document.body.appendChild(modal);
        document.getElementById('sessionContinueBtn')
            .addEventListener('click', _onSessionContinue);
    }

    function _showSessionWarning() {
        if (_sessionWarningShown) return;
        _sessionWarningShown = true;
        _previousFocusEl = document.activeElement;

        _ensureWarningModal();
        const modal = document.getElementById('sessionTimeoutModal');
        if (!modal) return;
        modal.hidden = false;
        modal.classList.add('is-open');

        // 15 sn countdown başlat
        let remaining = SESSION_LOGOUT_COUNTDOWN_SECONDS;
        const countdownEl = document.getElementById('sessionLogoutCountdown');
        const fillEl = document.getElementById('sessionCountdownFill');
        if (countdownEl) countdownEl.textContent = remaining;
        if (fillEl) fillEl.style.width = '100%';

        _logoutCountdownInterval = setInterval(() => {
            remaining--;
            const r = Math.max(0, remaining);
            if (countdownEl) countdownEl.textContent = r;
            if (fillEl) fillEl.style.width = ((r / SESSION_LOGOUT_COUNTDOWN_SECONDS) * 100) + '%';
            if (r <= 0) {
                clearInterval(_logoutCountdownInterval);
                _logoutCountdownInterval = null;
            }
        }, 1000);

        _logoutTimeoutId = setTimeout(_forceLogout, SESSION_LOGOUT_COUNTDOWN_SECONDS * 1000);

        // A11y: focus continue button
        setTimeout(() => {
            const btn = document.getElementById('sessionContinueBtn');
            if (btn) {
                try { btn.focus(); } catch (_) {}
            }
        }, 50);
    }

    function _hideSessionWarning() {
        if (_logoutTimeoutId) {
            clearTimeout(_logoutTimeoutId);
            _logoutTimeoutId = null;
        }
        if (_logoutCountdownInterval) {
            clearInterval(_logoutCountdownInterval);
            _logoutCountdownInterval = null;
        }
        const modal = document.getElementById('sessionTimeoutModal');
        if (modal) {
            modal.classList.remove('is-open');
            modal.hidden = true;
        }
        // Return focus
        if (_previousFocusEl && typeof _previousFocusEl.focus === 'function') {
            try { _previousFocusEl.focus(); } catch (_) {}
        }
        _previousFocusEl = null;
    }

    async function _onSessionContinue(e) {
        if (e) { e.preventDefault(); e.stopPropagation(); }
        const btn = document.getElementById('sessionContinueBtn');
        if (btn) {
            btn.classList.add('is-loading');
            btn.disabled = true;
        }
        try {
            // Refresh token ile yeni access token al
            if (window.VYRA_API && typeof window.VYRA_API.refreshToken === 'function') {
                await window.VYRA_API.refreshToken();
            }
            // Sayacı sıfırla — yeni 60 dk window
            sessionStartTime = new Date();
            localStorage.setItem('session_start_time', sessionStartTime.toISOString());
            _sessionWarningShown = false;
            _hideSessionWarning();
            if (window.showToast) {
                window.showToast('Oturumunuz yenilendi.', 'success');
            }
        } catch (err) {
            console.warn('[SessionTimeout] refresh hata, oturum uzatıldı (offline):', err);
            // Token refresh başarısız olsa bile oturumu uzat (offline/network hatası)
            sessionStartTime = new Date();
            localStorage.setItem('session_start_time', sessionStartTime.toISOString());
            _sessionWarningShown = false;
            _hideSessionWarning();
            if (window.showToast) {
                window.showToast('Oturum uzatıldı (bağlantı kontrol edin).', 'warning');
            }
        } finally {
            if (btn) {
                btn.classList.remove('is-loading');
                btn.disabled = false;
            }
        }
    }

    function _forceLogout() {
        _hideSessionWarning();
        try {
            localStorage.removeItem('access_token');
            localStorage.removeItem('refresh_token');
            localStorage.removeItem('session_start_time');
            localStorage.removeItem('user_data');
        } catch (_) {}
        if (sessionTimerInterval) {
            clearInterval(sessionTimerInterval);
            sessionTimerInterval = null;
        }
        // Login ekranı banner için query param
        window.location.href = 'login.html?reason=session_expired';
    }

    // --- SİDEBAR PROFİL ---
    async function loadSidebarProfile() {
        try {
            const token = localStorage.getItem('access_token');
            if (!token) return;

            const response = await fetch(`${API_BASE_URL}/api/users/me`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (response.ok) {
                const user = await response.json();

                const fullName = user.full_name || user.username || 'Kullanıcı';
                const nameEl = document.getElementById('sidebarUserName');
                if (nameEl) nameEl.textContent = fullName;

                localStorage.setItem('user_full_name', fullName);
                localStorage.setItem('user_name', user.username || '');

                // Avatar
                const avatarImgEl = document.getElementById('sidebarAvatarImg');
                const initialsEl = document.getElementById('sidebarAvatarInitials');

                if (user.avatar && avatarImgEl) {
                    avatarImgEl.src = user.avatar;
                    avatarImgEl.classList.remove('hidden');
                    if (initialsEl) initialsEl.classList.add('hidden');
                } else if (initialsEl) {
                    const initials = fullName.split(' ')
                        .map(word => word.charAt(0))
                        .slice(0, 2)
                        .join('')
                        .toUpperCase();
                    initialsEl.querySelector('span').textContent = initials || '?';
                    initialsEl.classList.remove('hidden');
                    if (avatarImgEl) avatarImgEl.classList.add('hidden');
                }

                // Rol rozeti
                const roleEl = document.getElementById('sidebarUserRole');
                if (roleEl) {
                    const roleName = user.role_name || user.role || 'user';
                    const roleDisplayNames = {
                        'admin': 'Yönetici', 'user': 'Kullanıcı', 'support': 'Destek',
                        'Admin': 'Yönetici', 'User': 'Kullanıcı'
                    };
                    roleEl.textContent = roleDisplayNames[roleName] || roleName;

                    const isAdmin = user.is_admin === true || user.is_admin === 1 ||
                        roleName === 'admin' || roleName === 'Admin';
                    if (isAdmin) { roleEl.classList.add('admin'); } else { roleEl.classList.remove('admin'); }
                    roleEl.classList.remove('hidden');
                }
            }
        } catch (err) {
            console.warn('[NGSSAI] Profil bilgisi yüklenemedi:', err);
        }
    }

    // --- SİSTEM SIFIRLAMA ---
    async function loadSystemResetInfo(companyId) {
        const protectedStats = document.getElementById("protectedStats");
        const deletableStats = document.getElementById("deletableStats");

        try {
            const qp = companyId ? `?company_id=${companyId}` : '';
            const data = await window.VYRA_API.request("/system/info" + qp);

            if (protectedStats && data.protected) {
                protectedStats.innerHTML = `
                    <span><i class="fa-solid fa-user-shield mr-2"></i>${data.protected.admin_users} admin</span>
                    <span class="ml-4"><i class="fa-solid fa-brain mr-2"></i>${data.protected.llm_configs} LLM</span>
                    <span class="ml-4"><i class="fa-solid fa-wand-magic-sparkles mr-2"></i>${data.protected.prompt_templates} prompt</span>
                    <span class="ml-4"><i class="fa-solid fa-database mr-2"></i>${data.protected.data_sources || 0} kaynak</span>
                `;
            }

            if (deletableStats && data.to_delete) {
                const d = data.to_delete;
                // v3.29.7: Agentic Query Learning tabloları toplamı (v3.21-v3.29 — 16 tablo)
                const agenticLearningTotal =
                    (d.learned_db_queries || 0) + (d.ds_synthetic_query_runs || 0) +
                    (d.ds_column_embeddings || 0) + (d.agentic_query_decisions || 0) +
                    (d.agentic_query_feedback || 0) + (d.agentic_size_observations || 0) +
                    (d.catboost_models || 0) + (d.few_shot_examples || 0) +
                    (d.business_glossary || 0) + (d.metric_definitions || 0) +
                    (d.synonym_suggestions || 0) + (d.pipeline_events || 0) +
                    (d.pipeline_traces || 0) + (d.user_preferences || 0) +
                    (d.ds_code_values || 0) + (d.learned_query_failures || 0);
                const total = (d.non_admin_users || 0) + (d.tickets || 0) + (d.dialogs || 0) +
                    (d.uploaded_files || 0) + (d.document_images || 0) + (d.rag_chunks || 0) +
                    (d.user_feedback || 0) + (d.document_topics || 0) +
                    (d.ml_training_samples || 0) + (d.ml_training_jobs || 0) +
                    (d.ml_training_schedules || 0) + (d.ml_models || 0) +
                    (d.learned_answers || 0) +
                    (d.ds_learning_results || 0) + (d.ds_db_objects || 0) +
                    (d.ds_discovery_jobs || 0) + (d.sql_audit_log || 0) +
                    (d.system_logs || 0) +
                    agenticLearningTotal;
                deletableStats.innerHTML = `
                    <span><i class="fa-solid fa-users mr-2"></i>${d.non_admin_users || 0} kullanıcı</span>
                    <span class="ml-4"><i class="fa-solid fa-ticket mr-2"></i>${d.tickets || 0} ticket</span>
                    <span class="ml-4"><i class="fa-solid fa-comments mr-2"></i>${d.dialogs || 0} dialog</span>
                    <span class="ml-4"><i class="fa-solid fa-file mr-2"></i>${d.uploaded_files || 0} dosya</span>
                    <span class="ml-4"><i class="fa-solid fa-puzzle-piece mr-2"></i>${d.rag_chunks || 0} chunk</span>
                    <span class="ml-4"><i class="fa-solid fa-robot mr-2"></i>${d.ml_models || 0} model</span>
                    <span class="ml-4"><i class="fa-solid fa-graduation-cap mr-2"></i>${d.learned_answers || 0} cevap</span>
                    <span class="ml-4"><i class="fa-solid fa-magnifying-glass-chart mr-2"></i>${d.ds_learning_results || 0} QA</span>
                    <span class="ml-4"><i class="fa-solid fa-table mr-2"></i>${d.ds_db_objects || 0} keşif</span>
                    <span class="ml-4"><i class="fa-solid fa-clipboard-list mr-2"></i>${d.sql_audit_log || 0} audit</span>
                    <span class="ml-4" data-tooltip="learned_db_queries + synthetic + embeddings + feedback + catboost + few-shot + glossary + metric + pipeline traces + user_preferences + ds_code_values + learned_query_failures (v3.29 Faz 6)"><i class="fa-solid fa-brain mr-2"></i>${agenticLearningTotal.toLocaleString('tr-TR')} agentic öğrenme</span>
                    <div class="mt-2 text-yellow-400"><strong>Toplam ${total.toLocaleString('tr-TR')} kayıt silinecek</strong></div>
                `;
            }
        } catch (err) {
            console.warn("[NGSSAI] Sistem bilgisi yüklenemedi:", err);
            if (protectedStats) protectedStats.innerHTML = '<span class="text-gray-500">Bilgi yüklenemedi</span>';
            if (deletableStats) deletableStats.innerHTML = '<span class="text-gray-500">Bilgi yüklenemedi</span>';
        }
    }

    function performSystemReset() {
        window.VyraModal.danger({
            title: "Dikkat! Bu İşlem Geri Alınamaz",
            message: "Tüm ticket'lar, dialog'lar, RAG dosyaları, ML eğitim verileri, öğrenilmiş cevaplar, DS öğrenme verileri, agentic query öğrenme (v3.21–v3.29: learned_db_queries, synthetic, embeddings, feedback, CatBoost modelleri, few-shot, glossary, metric, pipeline traces, user prefs, ds_code_values, learned_query_failures), SQL audit logları ve sistem logları silinecek. Kaynak tanımları, admin kullanıcılar, LLM ve Prompt ayarları korunacak.",
            confirmText: "Sistemi Sıfırla",
            cancelText: "İptal",
            onConfirm: async () => {
                const btn = document.getElementById("btnSystemReset");
                if (btn) {
                    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Sıfırlanıyor...';
                    btn.disabled = true;
                }
                try {
                    const result = await window.VYRA_API.request("/system/reset", { method: "POST" });
                    if (result.success) {
                        window.VyraModal.success({
                            title: "Sistem Sıfırlandı",
                            message: "Tüm veriler başarıyla temizlendi. Login sayfasına yönlendiriliyorsunuz...",
                            confirmText: "Tamam",
                            onConfirm: () => {
                                localStorage.removeItem("access_token");
                                localStorage.removeItem("refresh_token");
                                localStorage.removeItem("user_data");
                                window.location.href = "login.html";
                            }
                        });
                    }
                } catch (err) {
                    console.error("[NGSSAI] Sistem sıfırlama hatası:", err);
                    window.VyraModal.error({
                        title: "Sıfırlama Hatası",
                        message: err.message || "Bilinmeyen bir hata oluştu"
                    });
                    if (btn) {
                        btn.innerHTML = '<i class="fa-solid fa-rotate-left"></i> Sistemi Sıfırla';
                        btn.disabled = false;
                    }
                }
            }
        });
    }

    // --- EVENT LISTENERS ---
    const btnSystemReset = document.getElementById("btnSystemReset");
    if (btnSystemReset) btnSystemReset.addEventListener("click", performSystemReset);

    // Sidebar profil alanına tıklanınca profil sayfasına git
    const sidebarProfileArea = document.getElementById('sidebarProfileArea');
    if (sidebarProfileArea) {
        sidebarProfileArea.addEventListener('click', () => {
            const profileMenu = document.getElementById('menuProfile');
            if (profileMenu) profileMenu.click();
        });
    }

    // --- INIT (otomatik çalıştır) ---
    loadAppVersion();
    loadSidebarProfile();
    startSessionTimer();

    // --- PUBLIC API ---
    return {
        loadVersion: loadAppVersion,
        loadProfile: loadSidebarProfile,
        loadResetInfo: loadSystemResetInfo,
        performReset: performSystemReset,
        startTimer: startSessionTimer,
    };

})();

// Backward-compat aliases
window.loadAppVersion = window.SystemManagerModule.loadVersion;
window.loadSidebarProfile = window.SystemManagerModule.loadProfile;
window.loadSystemResetInfo = window.SystemManagerModule.loadResetInfo;
window.performSystemReset = window.SystemManagerModule.performReset;
window.startSessionTimer = window.SystemManagerModule.startTimer;


